export declare const REPORT_UX_SCRIPT = "\n    (function () {\n      var fill = document.querySelector(\".kca-progress-fill\");\n      var backTop = document.querySelector(\".kca-back-top\");\n      var topbar = document.querySelector(\".kca-topbar\");\n      var navLinks = document.querySelectorAll(\".deck-nav a[data-kca-jump], .hero-jump[data-kca-jump]\");\n      var sections = [];\n      navLinks.forEach(function (a) {\n        var id = a.getAttribute(\"data-kca-jump\");\n        if (!id) return;\n        var el = document.getElementById(id);\n        if (!el) return;\n        if (sections.some(function (s) { return s.el === el; })) return;\n        sections.push({ el: el, link: a });\n      });\n      function topbarOffset() {\n        return topbar ? topbar.getBoundingClientRect().height + 10 : 112;\n      }\n      function onScroll() {\n        var st = window.scrollY || document.documentElement.scrollTop;\n        var max = Math.max(1, document.documentElement.scrollHeight - window.innerHeight);\n        if (fill) fill.style.width = Math.min(100, (st / max) * 100) + \"%\";\n        if (backTop) backTop.hidden = st < 480;\n        if (!sections.length) return;\n        var probe = st + topbarOffset();\n        var current = sections[0];\n        for (var i = 0; i < sections.length; i += 1) {\n          if (sections[i].el.offsetTop <= probe) current = sections[i];\n        }\n        sections.forEach(function (s) {\n          var on = s === current;\n          s.link.classList.toggle(\"is-active\", on);\n          if (on) s.link.setAttribute(\"aria-current\", \"location\");\n          else s.link.removeAttribute(\"aria-current\");\n        });\n      }\n      window.addEventListener(\"scroll\", onScroll, { passive: true });\n      window.addEventListener(\"resize\", onScroll, { passive: true });\n      onScroll();\n      if (backTop) {\n        backTop.addEventListener(\"click\", function () {\n          window.scrollTo({ top: 0, behavior: \"smooth\" });\n        });\n      }\n      var shell = document.querySelector(\".deck-nav-shell\");\n      if (shell) {\n        shell.addEventListener(\"toggle\", function () {\n          setTimeout(function () {\n            onScroll();\n            window.dispatchEvent(new Event(\"resize\"));\n          }, 60);\n        });\n      }\n      var reduce = window.matchMedia && window.matchMedia(\"(prefers-reduced-motion: reduce)\").matches;\n      if (!reduce && typeof IntersectionObserver !== \"undefined\") {\n        var reveal = new IntersectionObserver(\n          function (entries) {\n            entries.forEach(function (en) {\n              if (en.isIntersecting) {\n                en.target.classList.add(\"is-inview\");\n                reveal.unobserve(en.target);\n              }\n            });\n          },\n          { rootMargin: \"0px 0px -5% 0px\", threshold: 0.05 },\n        );\n        var ri = 0;\n        document.querySelectorAll(\".card, .wrapped-card, .viz-card, .fact-card\").forEach(function (el) {\n          el.classList.add(\"kca-reveal\");\n          el.style.setProperty(\"--reveal-delay\", Math.min(ri * 35, 280) + \"ms\");\n          ri += 1;\n          reveal.observe(el);\n        });\n      }\n      function syncThemeButtons() {\n        var mode = document.documentElement.getAttribute(\"data-theme\") || \"system\";\n        document.querySelectorAll(\".theme-btn\").forEach(function (btn) {\n          var v = btn.getAttribute(\"data-theme-set\") || \"system\";\n          var on = mode === \"system\" ? v === \"system\" : v === mode;\n          btn.classList.toggle(\"is-active\", on);\n          btn.setAttribute(\"aria-pressed\", on ? \"true\" : \"false\");\n        });\n      }\n      var obs = new MutationObserver(function () {\n        syncThemeButtons();\n        setTimeout(function () { window.dispatchEvent(new Event(\"resize\")); }, 40);\n      });\n      obs.observe(document.documentElement, { attributes: true, attributeFilter: [\"data-theme\"] });\n      syncThemeButtons();\n      document.querySelectorAll(\".theme-btn\").forEach(function (btn) {\n        btn.addEventListener(\"click\", function () {\n          if (reduce) return;\n          btn.classList.remove(\"kca-ripple\");\n          void btn.offsetWidth;\n          btn.classList.add(\"kca-ripple\");\n          setTimeout(function () { btn.classList.remove(\"kca-ripple\"); }, 500);\n        });\n      });\n      if (!reduce && window.matchMedia(\"(hover: hover)\").matches) {\n        document.querySelectorAll(\".card, .wrapped-card, .viz-card, .insight-hero\").forEach(function (el) {\n          el.addEventListener(\"mousemove\", function (ev) {\n            var r = el.getBoundingClientRect();\n            var x = ((ev.clientX - r.left) / r.width) * 100;\n            var y = ((ev.clientY - r.top) / r.height) * 100;\n            el.style.setProperty(\"--kca-spot-x\", x + \"%\");\n            el.style.setProperty(\"--kca-spot-y\", y + \"%\");\n          });\n          el.addEventListener(\"mouseleave\", function () {\n            el.style.removeProperty(\"--kca-spot-x\");\n            el.style.removeProperty(\"--kca-spot-y\");\n          });\n        });\n      }\n    })();\n";
export declare const REPORT_EXPLORER_SCRIPT = "\n    (function () {\n      var el = document.getElementById(\"kca-explorer-data\");\n      var stats = document.getElementById(\"kca-explorer-stats\");\n      var from = document.getElementById(\"kca-range-from\");\n      var to = document.getElementById(\"kca-range-to\");\n      if (!el || !stats || !from || !to) return;\n      var data;\n      try { data = JSON.parse(el.textContent || \"{}\"); } catch (e) { return; }\n      if (!data.daily || !data.daily.length) return;\n      function sumRange(f, t) {\n        var msgs = 0, days = 0;\n        data.daily.forEach(function (d) {\n          if (d.date >= f && d.date <= t) {\n            msgs += d.count;\n            if (d.count > 0) days += 1;\n          }\n        });\n        return { msgs: msgs, days: days };\n      }\n      function render() {\n        var f = from.value, t = to.value;\n        if (f > t) { var tmp = f; f = t; t = tmp; }\n        var s = sumRange(f, t);\n        stats.innerHTML = \"<p><strong>\uC120\uD0DD \uAD6C\uAC04</strong> \" + f + \" ~ \" + t + \" \u00B7 \uBA54\uC2DC\uC9C0 <strong>\" + s.msgs.toLocaleString(\"ko-KR\") + \"</strong>\uAC74 \u00B7 \uD65C\uB3D9\uC77C <strong>\" + s.days + \"</strong>\uC77C</p>\";\n        if (typeof echarts === \"undefined\" || !document.getElementById(\"chart-explorer-daily\")) return;\n        var chart = echarts.getInstanceByDom(document.getElementById(\"chart-explorer-daily\"));\n        if (!chart) {\n          chart = echarts.init(document.getElementById(\"chart-explorer-daily\"));\n        }\n        var filtered = data.daily.filter(function (d) { return d.date >= f && d.date <= t; });\n        chart.setOption({\n          xAxis: { type: \"category\", data: filtered.map(function (d) { return d.date.slice(5); }) },\n          yAxis: { type: \"value\" },\n          series: [{ type: \"bar\", data: filtered.map(function (d) { return d.count; }) }],\n          grid: { left: 40, right: 12, top: 12, bottom: 28 },\n        });\n      }\n      from.addEventListener(\"change\", render);\n      to.addEventListener(\"change\", render);\n      render();\n    })();\n";
